def webUpdatePriceValidityView(node) {

    	/* INFO ms: 
    	   from_date: Sichtbarkeit für das Umschaltmenu, ab diesem Datum wird es angezeigt
    	   Zusatz 1: wer in canCalcOldPrice Liste ist sieht das Menu immer.
    	   to_date: Alte Preise bis zu diesem Datum möglich, ab to_date+1 sind die Preise neu.
    	   Zusatz 2: USM kann noch 90 Tage über das to_date alte Preise setzen und sieht deshalb das Umschaltmenu solange noch

    	  */

	   	my currency = NodeValue(node,'currency');

    	my validity_row = PRICE_VALIDITY['currency', currency];
   		global VALIDITY = validity_row;
   		global usm_price_gap = 0;
   		global view_old_price = false;
    	if (VALIDITY) {
	    	global validdate_view_priceold = Date(validity_row['to_date']);
			usm_price_gap = Number(validdate_view_priceold - ActualDate());
			view_old_price = Number(Date(validity_row['from_date']) - ActualDate()) le 0;
    	};

	};

def setOldPriceValid() {
				if (not call isUSM() or Scenario() eq 'web') {
				    usm_price_gap ge 0;
				}else{
				   usm_price_gap gt -90;
				};
			};

def isOldPriceValid() {       
      usm_price_gap ge 0;
		};

def getPriceKey(node) {
		my curr	= NodeValue(node,'calculation_currency');
		curr = StrLen(curr) ? curr : 'CHF';

	     /*  Für Einsatz alt und neu Preis: */
	     if (call setOldPriceValid()) {
	         my key = 'Preis_alt_' ++ curr;
	     } else { 
	     	'Preis_' ++ curr;
	     };
	};

