				def formatDistanceWeb(distance) {
          return call formatDistanceWeb(distance, UnitSystem() eq 'metric');
        }

				def formatDistanceWeb(distance, metric) {
          distance = distance *10;
          if (not metric) {
            return StrReplace(FormatImperialLength(distance, false, 2), ASCIIChar(8243), ASCIIChar(34));
          }
          return LocalizeNumber(Round(distance, 1)) ++ ' mm';
        }

