def hasPartsOnPrintZone(usmzone) {
	my p1= Vector(0,0,-10);
	my p2= Vector(0,0,400);
	/*p1 and p2 define the intersection ray in the local coordinate system of the 
	 part*/
	my zonepos = PolyCentroid(usmzone['pointlist']); 
	my center= VectorAdd(zonepos, p1);
	my direction= VectorSub(VectorAdd(zonepos,p2), center);
	/* center and direction are now in the global coordinate system */
	my info= GetIntersectionInfo(1000, Line(center, direction),'', null);

	if (info['part'] ne null) {
	  return true;
	} else {
	  return false;
	};
};

def setCategory(id) {
			my state = false;
		  if (id eq 'blacklines') {
		  	state = IsSubTypeOf('rohr') or IsSubTypeOf('kugel') or 
				        IsSubTypeOf('tischbein') or IsSubTypeOf('tischzarge') or 
				        IsSubTypeOf('ct_saeule') or IsSubTypeOf('traegerrohr') or 
				        IsSubTypeOf('ct_saeule_e_tisch') or IsSubTypeOf('ct_saeule_m_tisch');
      } else if (id eq 'onlylines') {
						state = IsSubTypeOf('ct_tischblatt');
			} else if (id eq 'transparent') {  	
						state = (IsSubTypeOf('haller_shelf_component') or 
		                 IsSubTypeOf('ct_primo') or 
		                 IsSubTypeOf('haller_table_component') or 
		                 IsSubTypeOf('ct_kitos_component') or 
		                 IsSubTypeOf('ct_kastenset')) 
		                 and not call setCategory('blacklines')
		                 and not IsSubTypeOf('tischblatt') 
		                 and not call setCategory('onlylines');
		      }
      return state;
    }

def hasInvalidVolumes() {
	my sub_assemblies = ChildrenListOfTypeDeep(Forest('mainstructure'), 'sub_assembly');
	return Size(sub_assemblies) gt 0;
};

def getSelectedVolumeList() {
	return call hasInvalidVolumes() ? List() : FilterList(GetVolumeList(), 'v', `not (IsSelected('mainstructure',v));`);
};

def isVolumeOnSide(volume, side) {
	my volumes = Feature(volume, 'f_volumes_list');

	if (Size(volumes)) {
		return InList(call getVolumesOnSide(volumes, side), volume);
	};

	return false;
};

def getVolumesOnSide(volumes, side) {
	my filterstr = '';
	my refpart = SortByValue(volumes, `Round(RelativePartPos(element, volumes[0])['x']);`)[0];
	if (side eq 'left') {
		volumes = SortByValue(volumes, `-Round(RelativePartPos(element, refpart)['x']);`);
		my ref_x = Round(RelativePartPos(volumes[0], refpart)['x']);
		filterstr = `my x = Round(RelativePartPos(p, refpart)['x']); 
		my ok = (x) eq ref_x;
		not ok;`;
		volumes = FilterList(volumes, 'p', filterstr);

	} else 
	if (side eq 'right') {
		volumes = SortByValue(volumes, `Round(RelativePartPos(element, refpart)['x']);`);
		my ref_x = Round(RelativePartPos(volumes[0], refpart)['x']);
		filterstr = `my x = Round(RelativePartPos(p, refpart)['x']); 
		my ok = (x) eq ref_x;
		not ok;`;
		volumes = FilterList(volumes, 'p', filterstr);
	} else 
	if (side eq 'top') {
		volumes = SortByValue(volumes, `Round(RelativePartPos(element, refpart)['z']);`);
		my ref_z = Round(RelativePartPos(volumes[0], refpart)['z']);
		filterstr = `my z = Round(RelativePartPos(p, refpart)['z']); 
		my ok = (z) eq ref_z;
		not ok;`;
		volumes = FilterList(volumes, 'p', filterstr);
	}; 

	volumes;
};

def getAllVolumesOfConnectionId(part) {
	my volumes = GetVolumeList();
	my connectionid = ConnectionId(part);
	volumes = FilterList(volumes, 'p', `not (ConnectionId(p) eq connectionid);`);
	volumes = SortByValue(volumes, `-Round(RelativePartPos(element, part)['z']);`);
	volumes;
};

def getVolumesInColumn(startvolume, part) {
