def sectionActive(section) {
		return EnvValue('ActiveSection', 'struktur') eq section and not Bool(CO_GLOBAL['resize']['problem']); 
};

def tableMaterialEnabled(material) {
	my tisch = call getTisch();
	my tischblatt = tisch ? ChildOfType(tisch, 'tischblatt') :  null;
	my length = tischblatt ? PartAttr(tischblatt, 'laenge') : '';
	my depth = tischblatt ? PartAttr(tischblatt, 'breite') : '';
	if ( material eq 'glas' and length gt 200){
		return false;
	};

	if (material eq 'holz' or material eq 'mdf' or material eq 'glas') {
		return depth ne '50';
	};

	return true;
};

def isBaseVolume(volume) {

	return PartAlive(volume) and GetVolumeList()[0] eq volume ;


};

def getHintVolumes(type, inside) {
	my volumes = GetVolumeList();
	volumes = inside ? FilterList(volumes, 'v', `ChildOfTypeDeep(v, 'glastuerset');`) : FilterList(volumes, 'p', `not (ChildCount(p) eq 0);`);

	my result = List();
	my hintvolumes = List();

	my columns = List();
	my values = List();

	my content_table = FilterList(VOLUME_CONTENT, 'e', `not (e['type'] ~ type);`);
	if (Size(content_table)) {
		for (my v: volumes) {
			if (content_table[0]['height'] eq 'floating') {
				columns = List('width', 'depth');
				values = String(List(Feature(v, 'xlength')*10, Feature(v,'ylength')*10));
			};

			if (Size(TableRows(content_table, columns,values, false))) {
				ListAdd(hintvolumes, v);
			}; 
		}

	};

	hintvolumes;
};

def calc_preis(articlenr) {
	call calc_preis(articlenr, true);
};
def calc_preis(articlenr, with_vep_factor) {
	//my articlenr= articlerow['articlenr'];
	my pricekey = call getPriceKey(NamedNode('documentsettings'));
	my color = SubStr(articlenr, IndexOfSubStr(articlenr, '.')+1);
	my spez_color= EndsWith(articlenr,'.99');
	articlenr= spez_color ? StrReplace(articlenr,'.99','.__'): articlenr;
	my spez_lock=EndsWith(articlenr,'.999');
	my specialcolorcostfactor = 100;
	my spez_color_factor = 1 + 100 / 100;
	my spez_lock_factor = 1 + 100 / 100;
	my val= 0;
	my spez = 'false';
	my vep_price_factor = 1;
	if (spez ne 'true') {
	  val =  BASE['Anr',articlenr][pricekey];

	  /* ms: wenn article nicht gefunden, suche in ECO (nur für fr-fr relevant) */
	  if (StrLen(val) eq 0) {
	  	val = ECO['Anr',articlenr][pricekey];
	  };
	  if (with_vep_factor) {
	  	vep_price_factor = NodeValue(NamedNode('documentsettings'), 'vep_price_factor'); 
	  };
	  my factor = NodeValue(NamedNode('documentsettings'), 'country_price_factor') * vep_price_factor;
	  val = val * 1;
	  /* TEST: Rundungsfehler
		val = spez_color ? Round(Round(val * spez_color_factor ,0.000000001),0.01):Round(Round(val,0.000000001),0.01);
		val = spez_lock ? Round(Round(val * spez_lock_factor ,0.000000001),0.01) : Round(Round(val,0.000000001),0.01);
		*/
		val = Round(val * factor ,0.000000001);
	}else{
	  val = -99999.99;
	} ;
	if (EndsWith(color,'_xxx')) {
	  val= 99999.99;
	}
  val;
	};

def sizeAvailable(hint, size) {
	return Bool(g_table[hint]['size',size]['available']);
};

def sizeEnabled(hint, size) {
	my with_content = Env('Volume.ResizeWithContent', 'true');
	call sizeEnabled(hint, size, with_content)
};
def sizeEnabled(hint, size, with_content) {
	my mode = call getInteractionMode();

	my ok = false;

	if (mode ne 'none' and not with_content) {
		ok = Bool(g_table[hint]['size',size]['selected']);
	} else {
		if (with_content) {
			ok = Bool(g_table[hint]['size',size]['available_if_empty']);

			/* ms: check for pflanzen volumes to disable size change */
			if (ok and hint eq 'height' and size lt 175) {
				my volumes = List();
				my selected_volumes = call getSelectedVolumeList();
				for (my v: selected_volumes) {
					ListExtend(volumes, call getVolumesInRow(v));
				}
				if (not Size(volumes) gt 0)  {
					volumes = GetVolumeList();	
				}

				my svolumes = List();
				for (my v: volumes) {
					my is_pflanzen_volume = Size(call getAllPflanzenOfVolume(v)) gt 0;
					is_pflanzen_volume ? ListAdd(svolumes, v) : null;

				}
				return Size(svolumes) eq 0;
			} else 
			if (ok and (hint eq 'width' or hint eq 'length') and size lt 350) { /* tiefe oder breite kleiner 350 */
				my volumes = List();
				my selected_volumes = call getSelectedVolumeList();
				for (my v: selected_volumes) {
					ListExtend(volumes, call getVolumesInColumn(v));
				}
				if (not Size(volumes) gt 0)  {
					volumes = GetVolumeList();	
				}

				my svolumes = List();
				for (my v: volumes) {
					my is_inos_volume = Size(ChildrenListOfTypeDeep(v, 'kastenset')) gt 0;
					is_inos_volume ? ListAdd(svolumes, v) : null;

				}
				return Size(svolumes) eq 0;
			} else {
				return ok;
			};
		} else {
			ok = Bool(g_table[hint]['size',size]['available_if_empty']);
		}
	};
	if (ok) {
		my volumes = call getSelectedVolumeList();
		if (Size(volumes) eq 0 ) {
			volumes = GetVolumeList();
			if (Size(volumes) gt 0) {
				my fname = hint eq 'width' ? 'ylength' : hint eq 'length' ? 'xlength' : 'zlength';
				my vsize = Round(Feature(volumes[0], fname) *10);
				my values = UniqueList(FeatureValuesFromPartList(volumes, fname));
				if (Size(values) gt 1) {
					return true;
				}

				my vsizes = List();

				for (my e: values) {
					ListAdd(vsizes, e*10);
				};

				if (InList(vsizes, Number(size))) {
					return false;
				};
			};
		};
		my check_volumes = List();
		if (hint eq 'width' and Size(volumes) gt 0) {
			check_volumes = call getAllVolumesOfConnectionId(volumes[0]);
		} else { 
		for (my v: volumes) {
				if (hint eq 'width') {

				} else {
					hint eq 'length' ? ListExtend(check_volumes, call getVolumesInColumn(v)) : ListExtend(check_volumes, call getVolumesInRow(v));
				}
			}
		};


		if (not Env('Volume.ResizeWithContent', 'true')) {
			for (my v: check_volumes) {
				if (ChildCount(v) gt 0) {
					ok = false;
					break;
				}
			};
		};
	}	
	return ok;
};

def currentSize(hint, size) {

	my mode = call getInteractionMode();

	my ok = false;
	my volumes = call getSelectedVolumeList();
	if (Size(volumes) eq 0 ) {
		volumes = GetVolumeList();
	};
	my ok = false;
	if (Size(volumes)) {
		my check_volumes = List();
		my size_list = List();
		if (hint eq 'width') {
			size_list = UniqueList(FeatureValuesFromPartList(volumes, 'ylength'));
		} else 
		if (hint eq 'length') {
			size_list = UniqueList(FeatureValuesFromPartList(volumes, 'xlength'));
		} else 
		if (hint eq 'height') {
			size_list = UniqueList(FeatureValuesFromPartList(volumes, 'zlength'));
		}

		my vsizes = List();

		for (my e: size_list) {
			ListAdd(vsizes, e*10);
		};

		if (InList(vsizes, Number(size))) {
			return true;
		};

	}	
	return ok;
};

def getSelectionOfType(type) {
