};

def hasContentOfType(volumes, type) {
	call hasContentOfType(volumes, type, '');
};
def hasContentOfType(volumes, type, filtercontenttype) {
	my result = false;
	for (my v: volumes) {
		my children = FilterList(ChildrenListOfTypeDeep(v, type), 'p', `IsSubTypeOf(p, filtercontenttype);`);
		if (Size(children) gt 0) {
			result = true;
			break;
		};

	};

	return result;

};

def getInteractionMode() {
	return EnvValue('InteractionMode', 'none');
}

def checkInteractionMode(mode) {
	return call getInteractionMode() eq mode;
}

def getFocusPointList(volume) {
	my volumes = Feature(volume, 'f_volumes_list');
	my base = FilterList(volumes, 'v', `not (call isBaseVolume(v));`)[0];
	my bbox = base ? Feature(base, 'bbox') : null;
	my offset = 50;
	my p1 = PartPos(base); p1['y'] = p1['y'] - 100;
	my p2 = VectorAdd(p1, Vector(bbox['extent']['x']+offset, 0,0));
	my p3 = VectorAdd(p2, Vector(0, 0, bbox['extent']['z']+offset));
	my p4 = VectorAdd(p1, Vector(0, 0, bbox['extent']['z']+offset));

	my pointlist = List(p1,p2,p3,p4);
}

