def isInBetweenColumn(volumes) {

	my result = false;

	if (Size(volumes)) { 
		my has_left = false;
		my has_right = false;
		for (my volume: volumes) { 
			my left = GetNeighbourVolume(volume, 3)[0];
			my right = GetNeighbourVolume(volume, 1)[0];
			has_left = not has_left ? left and not IsSelected('mainstructure', left) : has_left;
			has_right = not has_right ? right and not IsSelected('mainstructure', right) : has_right;

			result = has_left and has_right;

			if (result) {

				break;
			};
		}
	 }	

	return result;
}

def isInBetweenRow(volumes) {

	my result = false;

	if (Size(volumes)) { 
		my has_top = false;
		my has_bot = false;
		for (my volume: volumes) { 
			my top = GetNeighbourVolume(volume, 5)[0];
			my bot = GetNeighbourVolume(volume, 4)[0];
			has_top = not has_top ? top and not IsSelected('mainstructure', top) : has_top;
			has_bot = not has_bot ? bot and not IsSelected('mainstructure', bot) : has_bot;

			result = has_top and has_bot;

			if (result) {

				break;
			};
		}
	 }	

	return result;
}

def allBottomVolumesSelected(volumes) {

	my result = false;

	if (Size(volumes)) { 
		my has_top = false;
		my has_bot = false;
		for (my volume: volumes) { 
			my bot = GetNeighbourVolume(volume, 4)[0];
			if (not bot) {
				my bottomrow = call getVolumesInRow(volume);
				my selectedbottomrow = FilterList(bottomrow, 'v', `not (IsSelected('mainstructure', v));`);
				if (Size(selectedbottomrow) eq Size(bottomrow)) {
					return true;
				} else {
					my bottomcolumn = call getVolumesInColumn(volume);
					my selectedbottomcolumn = FilterList(bottomcolumn, 'v', `not (IsSelected('mainstructure', v));`);
					return Size(selectedbottomcolumn) ne Size(bottomcolumn);
				};
			};

		}
	 }	

	return result;
}

def checkBlechColor(given_color) {
		my ctList = GetSelectedComponentList('mainstructure');
		if (Size(ctList) eq 0) {
			ctList = GetComponentList();
		}

		my filterstr = `not (not IsSubTypeOf(e, 'kugel') and not IsSubTypeOf(e, 'rohr') and not IsSubTypeOf(e, 'bodenelement') and PropertyActive(e, 'metallverkleidungsFarbe_lokal'));`;
		my filteredCTList = FilterList(ctList, 'e', filterstr);
		my colors = FeatureValuesFromPartList(filteredCTList, 'Metallfarbe');

		my uniqueColors = UniqueList(colors);

		InList(uniqueColors, given_color) or call checkKastensetFarbe(given_color);
	} ;

def checkKastensetFarbe(given_color){
		my ctList = GetSelectedComponentList('mainstructure');
		if (Size(ctList) eq 0) {
			ctList = GetComponentList();
		}

		my filterstr = `not (IsSubTypeOf(e, 'ct_kastenset') and PropertyActive(e, 'schalentypmaterialfarbig'));`;
		my filteredCTList = FilterList(ctList, 'e', filterstr);
		my color = FeatureValuesFromPartList(filteredCTList, 'Schalentypmaterialfarbig');
		my uniqueColors = UniqueList(color);
		InList(uniqueColors, given_color);
	};

def colorList() {
	return call colorList(false);
};
def colorList(volumesonly) {
	my ctList = GetSelectedComponentList('mainstructure');
	if (Size(ctList) eq 0) {
		ctList = GetComponentList();
	}

	my filterstr = ``;
	if (volumesonly) {
		filterstr = `not (IsSubTypeOf(e, 'metallverkleidung') and not IsSubTypeOf(e, 'kugel') and not IsSubTypeOf(e, 'rohr') and not IsSubTypeOf(e, 'bodenelement') and HasFeature(e, 'Metallfarbe'));`;
	} else {
		filterstr = `not (not IsSubTypeOf(e, 'kugel') and not IsSubTypeOf(e, 'rohr') and not IsSubTypeOf(e, 'bodenelement') and HasFeature(e, 'Metallfarbe'));`;
	};
	my filteredCTList = FilterList(ctList, 'e', filterstr);
	my colors = FeatureValuesFromPartList(filteredCTList, 'Metallfarbe');
	ListExtend(colors, FeatureValuesFromPartList(GetComponentListOfType('schalenkasten'), 'Schalentypmaterialfarbig'));
	my uniqueColors = UniqueList(colors);
	uniqueColors;
} ;

def kugelPosition() {
	my selectedlist = GetComponentList();
	my kugel_list = FilterList(selectedlist,'element',`not IsSubTypeOf(element,'kugel');`);
	my kugel_table = List();

	for (my k : kugel_list)	
	{
		my row = List();
		row['pos_x'] = Round((PartPos(k)[0]), 0.05);
		row['pos_y'] = Round((PartPos(k)[1]), 0.05);

		ListAdd(kugel_table, row);
	}; kugel_table = CompressTable(kugel_table, List('pos_x', 'pos_y'),''); kugel_table; 
};

def rohrPosition() {
	my rohr_list = ComponentListWithFeatureValue('f_direction', 'Horizontal','rohr');
	my rohr_table = List();

	for (my r : rohr_list)
	{
		my row = List();
		row['pos_x'] = Round((PartPos(r)[0]), 0.05);
		row['pos_y'] = Round((PartPos(r)[1]), 0.05);
		row['rot_x'] = PartRot(r)[0];
		row['rot_y'] = PartRot(r)[1];
		row['rot_z'] = PartRot(r)[2];
		row['hc_len'] = PartAttr(r, 'hc_length');
		row['horizontal_front'] = Feature(r, 'f_horizontal_front') eq 'true' ? 'horiz' : 'vertic';

		ListAdd(rohr_table, row);
	}; rohr_table = CompressTable(rohr_table, List('pos_x', 'pos_y','hc_len','horizontal_front'),''); rohr_table;
};

def volumePosition() {
	my volumes = GetVolumeList();
	my volumes_table = List();

	for ( v : volumes)
	{
		my row = List();
		row['pos_x'] = Round((PartPos(v)[0]), 0.05);
		row['pos_y'] = Round((PartPos(v)[1]), 0.05);
		row['xlength'] =  Feature(v,'xlength')*10;
		row['ylength'] =  Feature(v,'ylength') * 10;

		ListAdd(volumes_table, row);
	}; volumes_table = CompressTable(volumes_table, List('pos_x', 'pos_y'),''); volumes_table;
};

def customLocalizeNumber(number, precision) {
	my num = StrReplace(LocalizeNumber(number, precision), ASCIIChar(8217), ASCIIChar(39));

	num;
};

def customLocalizeNumber(number) {
	my precision = NodeValue(NamedNode('documentsettings'), 'locale') eq 'ja-jp' ? 0 : 2;
	call customLocalizeNumber(number, precision);

};

def customLocalizeNumberWithCurrency(number, currency) {

	my locale = NodeValue(NamedNode('documentsettings'), 'locale');

	if (locale eq 'zh-cn'){
		number = Round(number);
	}

	my number = call customLocalizeNumber(number);
	my pre = InList(List('de-ch','fr-ch','it-ch','en-us','en-gb','en-nz','en-au', 'ja-jp'), locale);

	my space = locale eq 'ja-jp' or locale ~ '-ch' ? ' ' : '';

	if (pre) {
		return currency ++ space ++ number;
	};



	return number ++ ' '++currency;

};

def isKorpus(groupid) {
    my group_parts = call groupIdPartList(groupid);
    my dim = call groupIdDimemsions(group_parts,'both'); 
    my height = dim[0];
    my width = dim[1]; /* kurze Seite */
    my depth = dim[2]; /* lange Seite */
    my schubladen = GetComponentListOfType('schublade');
    my schublade = schubladen[0];
    if (schublade) { 
      my dim1 = width eq 395 and depth eq 500 and height lt 745;
      /* wdith wird zu depth, da breiter als tiefe */
      my dim2 = width eq 500 and depth eq 750 and height le 789;
      if (dim1 or dim2) { 
        return true;
      }
    }

   return false;
}

def isKorpus() {
			my groupidlist = call partGroupIdList('usm_haller');
			my is_korpus = Size(groupidlist) gt 0 and call isKorpus(groupidlist[0]);

			return is_korpus;
		};

