def getPriceConditions(locale) {
  	my price_conditions = '';
	my price_conditions_prefix = LOCALE['key', locale]['price_condition_prefix'];
	my price_conditions_url = 'price_condition_url';
	my price_conditions_name = LOCALE['key', locale]['price_condition_name'];

	my retail = StrLen(CO_GLOBAL['additionaldata']['key']) gt 0 and not Bool(CO_GLOBAL['additionaldata']['usm']);

	if (Size(price_conditions_prefix)) {
		price_conditions =  price_conditions_prefix;
	}
	if (StrLen(price_conditions_url) gt 0) { 
		if (StrLen(price_conditions_name)) {
		    if (retail) {
				price_conditions =  price_conditions;
			} else {
				price_conditions = price_conditions ++ ', ' ++ASCIIChar(60)++'a style='++ASCIIChar(34)++' text-decoration: underline; '++ASCIIChar(34)++ ' href='++ASCIIChar(34)++price_conditions_url++ASCIIChar(34)++ASCIIChar(62)++price_conditions_name++ASCIIChar(60)++'/a'++ASCIIChar(62);
			} 
		} else {
			price_conditions =  price_conditions ++ ASCIIChar(60) ++'a style='++ASCIIChar(34)++' text-decoration: underline; '++ASCIIChar(34)++ ' href='++ASCIIChar(34)++price_conditions_url++ASCIIChar(34)++ASCIIChar(62)++ASCIIChar(60)++'/a'++ASCIIChar(62); 
		}
	} else
	if (StrLen(price_conditions_name)) { 
		if (Size(price_conditions_name)) {
			price_conditions =  price_conditions ++ ', ' ++ ' <a href="' ++price_conditions_url++'">' ++ ' '++price_conditions_name; 
		}
	}


	return PXFormattingToHTML(price_conditions, true);

  }

def getSeitenVerkleidung() {	
	return FilterList(GetComponentListOfType('verkleidung'), 'p', `not (Abs(Round(PartRot(p)['y'])) eq 90);`);

};

def getTopBottomVerkleidung() {	
	return FilterList(GetComponentListOfType('verkleidung'), 'p', `not (Abs(Round(PartRot(p)['x'])) eq 0 and Abs(Round(PartRot(p)['y'])) eq 0);`);

};

def canDeleteVerkleidung(blech) {	

	my can_delete = true;
	my seitenverkleidung = call getSeitenVerkleidung();
	my topbottomverkleidung = call getTopBottomVerkleidung();
	if (InList(seitenverkleidung, blech)) {
		for (my v: GetRefVolumes(blech, 'mainstructure')) {
			my content = ChildOfType(v, 'volumecontent');
			if (content) {
				can_delete = (not ChildOfType(content, 'einbauset') or ChildOfType(content, 'schubladenauszugset')) and not ChildOfType(content, 'tablar'); 
			} else {
				can_delete = not ChildOfType(v, 'glastuerset');
			};
			if (not can_delete) {
				break;
			};
		};
	}
	if (can_delete and InList(topbottomverkleidung, blech)) {
		for (my v: GetRefVolumes(blech, 'mainstructure')) {
			my content = ChildOfType(v, 'volumecontent');
			if (content) {
				can_delete = not ChildOfType(content, 'schubladenauszugset');
			}
			if (can_delete and PartPos(blech)['z'] lt 8) {
				can_delete = not call isKorpus();
			}; 
			if (not can_delete) {
				break;
			};

		};
	}
	return can_delete;	
};

