	def getNextValidTischdepth(tisch, type){
		my tischblatt = ChildOfType(tisch, 'tischblatt');
		my tischbein = ChildOfType(tisch, 'tischbein');
		my hoehe = '74';
    	if (tischbein) {
    		if (GetTypeName(tischbein) ~ '_37') {
    			hoehe = '37';	
    		};
    	}

		my length =  PartAttr(tischblatt, 'laenge');
		my depth =  PartAttr(tischblatt, 'breite');
		my found = false;
		my next = depth;
		if (tischblatt){
			if (type eq 'larger') {
				while (not found and next lt 100) {
					next = String(next + 25);
					found = InTable(HALLERTISCH_SIZES, List('length', 'depth', 'height'), List(length, next, hoehe));
				}
				if (found) {
					depth = next;
				};
			} else
			if (type eq 'smaller') {
				while (not found and next gt 75) {
					next = String(next - 25);
					found = InTable(HALLERTISCH_SIZES, List('length', 'depth','height'), List(length, next, hoehe));
				}
				if (found) {
					depth = next;
				};
			}

		};	


		return depth;
	};

