def tableSizeEnabled(hint, size) {
	my result = false;
	my tisch = call getTisch();
	if (not tisch) {
		return false;
	};
	my hoehe = call getTableHeight(tisch);
	my tischblatt = ChildOfType(tisch,'tischblatt');
	my material = Feature(tischblatt, 'f_materialSubKategorie');
	if (hint eq 'length' and material eq 'glas' and size gt 200){
		return false;
	}
	if (hint eq 'depth') {
		my depth = size;
		my length = PartAttr(tischblatt, 'laenge');
		my height = hoehe;
	} else
	if (hint eq 'length') {
		my depth = PartAttr(tischblatt, 'breite');
		my length = size;
		my height = hoehe;

	} else 

	if (hint eq 'height') {
		my depth = PartAttr(tischblatt, 'breite');
		my length = PartAttr(tischblatt, 'laenge');
		my height = size;

	}

	result = InTable(HALLERTISCH_SIZES, List('length', 'depth', 'height'), List(length, depth, height));
};

def currentTableSize(hint, size) {
	my result = false;
	my tisch = call getTisch();
	if (not tisch) {
		return false;
	};
	my hoehe = call getTableHeight(tisch);
	my tischblatt = ChildOfType(tisch,'tischblatt');
	my material = Feature(tischblatt, 'f_materialSubKategorie');
	if (hint eq 'length'){
		return PartAttr(tischblatt, 'laenge') eq size;
	} else
	if (hint eq 'depth') {
		return PartAttr(tischblatt, 'breite') eq size;

	} else 

	if (hint eq 'height') {

		return hoehe eq size;

	}

};

