def partBelongsToVolumeList(part, volumes) {
			my result = false;
			my volume = ParentOfType(part, 'mainstructure', 'normal_volume');
			if (volume) {
				result = InList(volumes, volume);
			};
			if (result) {
				my refvolumes = GetRefVolumes(part, 'mainstructure');
				for (my v: refvolumes) {
					result = InList(volumes, v);
					if (result) {
						break;
					};
				};
			};

			return result;
		}

